// INICIO DE ROOTITER.form

function ListClick()
{ 
	var img;

	if (Ctrl("LIST"))
	{
		img=Ctrl("LIST").GetSelectAttrValue("img").toUpperCase().split("/");
		img=img[img.length-1].split(".")[0];

		switch(img)
		{
			case "LOCK":
				CtrlEnabled("EDIT"  ,false);
				CtrlEnabled("DELETE",false);
			break;
			case "LOCKDEL":
				CtrlEnabled("EDIT"  ,true );
				CtrlEnabled("DELETE",false);
			break;
			case "LOCKEDIT":
				CtrlEnabled("EDIT"  ,false);
				CtrlEnabled("DELETE",true );
			break;
			default:
				CtrlEnabled("EDIT"  ,true);
				CtrlEnabled("DELETE",true);
			break;
		}
	}

	if ((Ctrl("LockREG")) && (Ctrl("HiLockREG"))) 
	{                  

		Ctrl("LockREG").SetXValue(Ctrl("HiLockREG").GetXValue());
		CtrlEnabled("EDIT"  ,Ctrl("LockREG").GetXValue()!="1");
		CtrlEnabled("DELETE",Ctrl("LockREG").GetXValue()!="1");
	}
}

function ListDobleClick()
{             
	if (Ctrl("MOSTRAR")) 
		Ctrl("MOSTRAR").DoEvent("OnClick");
}

// FIN DE ROOTITER.form
